/**
 * WPMVC Debugger UI.
 *
 * Bootstrap's JS bundle is deliberately not used — its plugins toggle
 * unprefixed class names (`show`, `active`, ...) that don't exist in the
 * prefixed CSS build, so all behavior lives here. For the same reason,
 * state classes toggled from JS must use the prefixed names
 * (`wpmvc-active`, `wpmvc-d-none`, ...).
 */
( () => {
    const STORAGE_KEY = 'wpmvc-debug';

    document.addEventListener( 'DOMContentLoaded', () => {
        const root = document.querySelector( '.wpmvc-debug' );

        if ( ! root ) {
            return;
        }

        let state;

        try {
            state = JSON.parse( window.localStorage.getItem( STORAGE_KEY ) ) || {};
        } catch ( e ) {
            state = {};
        }

        state.theme  = 'dark' === state.theme ? 'dark' : 'light';
        state.pinned = !! state.pinned;
        state.open   = state.pinned && !! state.open; // only a pinned debugger survives a refresh

        const pin = root.querySelector( '[data-wpmvc-debug-pin]' );

        const save = () => window.localStorage.setItem( STORAGE_KEY, JSON.stringify( state ) );

        const apply = () => {
            root.setAttribute( 'data-bs-theme', state.theme );
            root.classList.toggle( 'wpmvc-debug-open', state.open );
            pin.classList.toggle( 'wpmvc-active', state.pinned );
        };

        const activateTab = ( name ) => {
            root.querySelectorAll( '[data-wpmvc-debug-tab]' ).forEach( ( el ) => {
                el.classList.toggle( 'wpmvc-active', name === el.dataset.wpmvcDebugTab );
            } );

            root.querySelectorAll( '[data-wpmvc-debug-pane]' ).forEach( ( el ) => {
                el.classList.toggle( 'wpmvc-d-none', name !== el.dataset.wpmvcDebugPane );
            } );
        };

        root.addEventListener( 'click', ( event ) => {
            const target = event.target;

            if ( target.closest( '[data-wpmvc-debug-toggle]' ) ) {
                state.open = ! state.open;
            } else if ( target.closest( '[data-wpmvc-debug-close]' ) ) {
                state.open = false;
            } else if ( target.closest( '[data-wpmvc-debug-theme-toggle]' ) ) {
                state.theme = 'dark' === state.theme ? 'light' : 'dark';
            } else if ( target.closest( '[data-wpmvc-debug-pin]' ) ) {
                state.pinned = ! state.pinned;
            } else {
                const tab = target.closest( '[data-wpmvc-debug-tab]' );

                if ( tab ) {
                    activateTab( tab.dataset.wpmvcDebugTab );
                }

                return;
            }

            apply();
            save();
        } );

        document.addEventListener( 'keydown', ( event ) => {
            if ( 'Escape' === event.key && state.open ) {
                state.open = false;
                apply();
                save();
            }
        } );

        apply();
    } );
} )();
